import { domainToActualRange } from '../tools/zoom-identity-by-domain';
import { defined, isArray } from '../../../../utils/zcutils';

/**
 *
 * @param eventManager
 * @param domain
 * @param type
 * @param seriesIndex
 * @param scale
 * @param transition
 * @private
 */
export function _BrushToDomain(eventManager, domain, type, seriesIndex, scale, transition) {
    let chart = eventManager.chart,
        plotBrush = eventManager.behaviours.PLOT_BRUSH,
        plotZoom = eventManager.behaviours.PLOT_ZOOM,
        range = type.split('').map((axisType, i) => {
            return domainToActualRange(chart, isArray(domain[0]) ? domain[i] : domain, seriesIndex, axisType, defined(plotZoom), false);
        });

    if (type === 'xy') {
        // range to selection
        range = [[range[0][0], range[1][0]], [range[0][1], range[1][1]]];
    } else {
        range = range[0];
    }

    plotBrush.instance.setSelection(range);
}
